def count_unique(nums):
    """
    Counts how many values appear exactly once in the list.

    Parameters:
    nums (list): The list of integers to be evaluated.

    Returns:
    int: The count of unique values that appear exactly once.
    """
    if not nums:
        return 0

    num_counts = {}
    for num in nums:
        if num in num_counts:
            num_counts[num] += 1
        else:
            num_counts[num] = 1

    return sum(1 for count in num_counts.values() if count == 1)
